// =======================================================
// KHỞI TẠO ỨNG DỤNG KHI TRÌNH DUYỆT TẢI XONG
// =======================================================
async function initApp() {
    try {
        // 1. Kiểm tra trạng thái đăng nhập (JWT Token)
        const token = localStorage.getItem('access_token');
        if (token) {
            App.isLoggedIn = true;
            try {
                const savedEmail = localStorage.getItem('current_user_email') || '';
                if (savedEmail) {
                    App.currentUser.email = savedEmail;
                }
                await Auth.loadAccountWorkspace();
            } catch (_err) {
                App.currentUser = { name: "Khách hàng", email: "user@email.com", role: 'CUSTOMER' };
            }
        }

        // 2. Fetch data (Sử dụng cách thức fetch an toàn)
        const response = await fetch(`${API_BASE_URL}/api/data/`);

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();

        if (data.success) {
            // Tối ưu: Dùng Object.assign để nạp state gọn gàng hơn
            Object.assign(App, {
                storeInfo: data.storeInfo,
                storeProducts: data.storeProducts,
                hotDeals: data.hotDeals,
                categories: data.categories
            });

            // Tự động sinh giao diện
            Store.renderStoreTabs();
            Store.renderHotDeals();
            Store.renderCatalog();

            // Lấy ID của cửa hàng đầu tiên để chọn mặc định an toàn
            const firstStoreId = Object.keys(data.storeInfo)[0];
            if (firstStoreId) {
                Store.selectStore(firstStoreId);
            }

            UI.updateAuthUI();
            UI.showHome();
            console.log("✅ Đã khởi tạo Intelishop thành công!");
        } else {
            throw new Error(data.message || "Dữ liệu server trả về không hợp lệ");
        }

    } catch (error) {
        console.error("Lỗi khi tải dữ liệu từ server:", error);
        // Fallback UI nếu server sập
        if (typeof UI.showNotification === "function") {
            UI.showNotification("Không thể kết nối máy chủ! Đang thử lại...", "error");
        }
    }
}

// Kích hoạt app an toàn
document.addEventListener('DOMContentLoaded', initApp);

import { API_BASE_URL, App } from './config.js';
import * as UI from './ui.js';
import * as Auth from './auth.js';
import * as Store from './store.js';
import * as Cart from './cart.js';
import * as Chatbot from './chatbot.js';

// =======================================================
// GẮN TOÀN BỘ HÀM LÊN WINDOW ĐỂ HTML ONCLICK GỌI ĐƯỢC
// =======================================================

// UI Navigation
window.showHome = UI.showHome;
window.showLogin = UI.showLogin;
window.showRegister = UI.showRegister;
window.showAccount = UI.showAccount;
window.showVendorApply = UI.showVendorApply;
window.showShipperApply = UI.showShipperApply;

// Auth
window.handleRegister = Auth.handleRegister;
window.handleLogin = Auth.handleLogin;
window.logout = Auth.logout;
window.checkPasswordStrength = Auth.checkPasswordStrength;
window.checkPasswordMatch = Auth.checkPasswordMatch;
window.togglePassword = Auth.togglePassword;
window.loadAccountWorkspace = Auth.loadAccountWorkspace;
window.saveProfile = Auth.saveProfile;
window.createAddress = Auth.createAddress;
window.setDefaultAddress = Auth.setDefaultAddress;
window.deleteAddress = Auth.deleteAddress;
window.submitVendorApplication = Auth.submitVendorApplication;
window.submitShipperApplication = Auth.submitShipperApplication;

// Store & Products
window.selectStore = Store.selectStore;
window.loadMoreProducts = Store.loadMoreProducts;
window.scrollStoreTabs = Store.scrollStoreTabs;
window.checkScrollButtons = Store.checkScrollButtons;
window.filterByCategory = Store.filterByCategory;
window.searchProducts = Store.searchProducts;
window.clearSearch = Store.clearSearch;

// Cart & Checkout
window.addToCart = Cart.addToCart;
window.showCart = Cart.showCart;
window.updateCartQty = Cart.updateCartQty;
window.removeFromCart = Cart.removeFromCart;
window.proceedToCheckout = Cart.proceedToCheckout;
window.nextStep = Cart.nextStep;
window.prevStep = Cart.prevStep;
window.selectShipping = Cart.selectShipping;
window.placeOrder = Cart.placeOrder;
window.showOrders = Cart.showOrders;

// Chatbot
window.toggleAIPanel = Chatbot.toggleAIPanel;
window.handleChatKeyPress = Chatbot.handleChatKeyPress;
window.sendChatMessage = Chatbot.sendChatMessage;
window.toggleVoiceRecording = Chatbot.toggleVoiceRecording;

// Wishlist
window.toggleWishlist = Auth.toggleWishlist;

// =======================================================
// KHỞI TẠO ỨNG DỤNG KHI TRÌNH DUYỆT TẢI XONG
// =======================================================
async function initApp() {
    try {
        // 1. Kiểm tra trạng thái đăng nhập (JWT Token)
        const token = localStorage.getItem('access_token');
        if (token) {
            App.isLoggedIn = true;
            try {
                const savedEmail = localStorage.getItem('current_user_email') || '';
                if (savedEmail) {
                    App.currentUser.email = savedEmail;
                }
                await Auth.loadAccountWorkspace();
            } catch (_err) {
                App.currentUser = { name: "Khách hàng", email: "user@email.com", role: 'CUSTOMER' };
            }
        }

        // 2. Fetch data (Sử dụng cách thức fetch an toàn)
        const response = await fetch(`${API_BASE_URL}/api/data/`);

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();

        if (data.success) {
            // Tối ưu: Dùng Object.assign để nạp state gọn gàng hơn
            Object.assign(App, {
                storeInfo: data.storeInfo,
                storeProducts: data.storeProducts,
                hotDeals: data.hotDeals,
                categories: data.categories
            });

            // Tự động sinh giao diện
            Store.renderStoreTabs();
            Store.renderHotDeals();
            Store.renderCatalog();

            // Lấy ID của cửa hàng đầu tiên để chọn mặc định an toàn
            const firstStoreId = Object.keys(data.storeInfo)[0];
            if (firstStoreId) {
                Store.selectStore(firstStoreId);
            }

            UI.updateAuthUI();
            UI.showHome();

            // Gắn sự kiện tìm kiếm với debounce 300ms
            const searchInput = document.getElementById('search-input');
            if (searchInput) {
                let searchDebounce;
                searchInput.addEventListener('input', (e) => {
                    clearTimeout(searchDebounce);
                    searchDebounce = setTimeout(() => {
                        const query = e.target.value.trim();
                        Store.searchProducts(query);
                        // Cuộn xuống khu vực sản phẩm khi tìm kiếm
                        if (query) {
                            const productsSection = document.getElementById('product-list');
                            if (productsSection) productsSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }
                    }, 300);
                });
                searchInput.addEventListener('keydown', (e) => {
                    if (e.key === 'Escape') Store.clearSearch();
                });
            }

            console.log("✅ Đã khởi tạo Intelishop thành công!");
        } else {
            throw new Error(data.message || "Dữ liệu server trả về không hợp lệ");
        }

    } catch (error) {
        console.error("Lỗi khi tải dữ liệu từ server:", error);
        // Fallback UI nếu server sập
        if (typeof UI.showNotification === "function") {
            UI.showNotification("Không thể kết nối máy chủ! Đang thử lại...", "error");
        }
    }
}

// Kích hoạt app an toàn
document.addEventListener('DOMContentLoaded', initApp);

import { App, storeFeedback, $, API_BASE_URL } from './config.js';

// Tối ưu ghép chuỗi URL tĩnh
const getFullUrl = (path) => {
    if (!path) return '';
    if (path.startsWith('http')) return path;
    const baseUrl = API_BASE_URL.replace(/\/$/, '');
    return `${baseUrl}${path.startsWith('/') ? path : `/${path}`}`;
};

export function renderStoreTabs() {
    const container = $('store-tabs-container');
    if (!container) return;

    // Tối ưu: map mảng sau đó gán 1 lần
    container.innerHTML = Object.keys(App.storeInfo).map((storeId, index) => {
        const info = App.storeInfo[storeId];
        const activeClass = App.currentStore == storeId ? 'active' : '';
        const textColor = index >= 3 ? 'text-white' : 'text-gray-800';

        const iconHtml = info.icon
            ? `<img src="${getFullUrl(info.icon)}" alt="${info.name}" class="w-12 h-12 object-contain bg-white rounded-full mb-2 border-2 border-pink-200 shadow-sm mx-auto p-1 transition-transform group-hover:scale-110">`
            : `<div class="w-12 h-12 bg-gray-200 rounded-full mb-2 mx-auto flex items-center justify-center text-gray-400"><i class="fa-solid fa-store"></i></div>`;

        return `
        <div class="store-card group ${activeClass}" id="store-tab-${storeId}" onclick="selectStore(${storeId})" style="background: ${info.bg_color}">
            ${iconHtml}
            <div class="store-name ${textColor} font-bold">${info.name}</div>
            <div class="store-stats ${textColor} opacity-90 text-xs mt-1"><i class="fa-solid fa-star text-yellow-300 mr-1"></i>${info.rating} • Đã bán ${info.sold}</div>
        </div>
        `;
    }).join('');
}

export function renderHotDeals() {
    const container = $('hot-deals-container');
    if (!container) return;

    if (!App.hotDeals || App.hotDeals.length === 0) {
        container.innerHTML = '<div class="col-span-full py-10 text-center text-gray-400 bg-gray-50 rounded-2xl"><i class="fa-solid fa-box-open text-4xl mb-3"></i><p>Hiện tại chưa có Deal Hot nào.</p></div>';
        return;
    }

    container.innerHTML = App.hotDeals.map(p => {
        let badgeHtml = '';
        let priceHtml = `<span class="text-xl font-black text-red-600">${p.price.toLocaleString('en-US')}₫</span>`;

        if (p.old_price && p.old_price > p.price) {
            const percent = Math.round((1 - p.price / p.old_price) * 100);
            badgeHtml = `<span class="absolute top-3 left-3 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded shadow-sm z-10">-${percent}%</span>`;
            priceHtml = `
                <span class="text-xl font-black text-red-600">${p.price.toLocaleString('en-US')}₫</span>
                <span class="text-xs text-gray-400 line-through block ml-1">${p.old_price.toLocaleString('en-US')}₫</span>
            `;
        }

        const imageHtml = p.image
            ? `<img loading="lazy" src="${getFullUrl(p.image)}" alt="${p.name}" class="w-full h-full object-cover transition-transform duration-500 hover:scale-110">`
            : `<div class="text-gray-300 text-4xl"><i class="fa-solid fa-image"></i></div>`;

        return `
        <div class="bg-white p-3 rounded-2xl relative border border-red-100 hover:border-red-400 shadow-sm hover:shadow-lg transition-all cursor-pointer group flex flex-col h-full">
            ${badgeHtml}
            <div class="h-40 sm:h-48 rounded-xl overflow-hidden mb-3 bg-gray-50 flex items-center justify-center relative">
                ${imageHtml}
            </div>
            <h3 class="font-bold text-gray-800 text-sm mb-2 line-clamp-2" title="${p.name}">${p.name}</h3>
            <div class="mt-auto flex items-end justify-between">
                <div>${priceHtml}</div>
                <button onclick="addToCart(${p.id})" class="bg-red-50 text-red-500 w-10 h-10 rounded-full flex items-center justify-center hover:bg-red-500 hover:text-white transition shadow-sm z-20 relative">
                    <i class="fa-solid fa-cart-plus"></i>
                </button>
            </div>
        </div>
        `;
    }).join('');
}

export function selectStore(storeId) {
    document.querySelectorAll('.store-card').forEach(card => card.classList.remove('active'));
    const activeTab = $(`store-tab-${storeId}`);
    if (activeTab) activeTab.classList.add('active');

    App.currentStore = storeId;
    App.currentVisibleProducts = App.productsPerPage;

    const info = App.storeInfo[storeId];
    if (!info) return;

    const iconDisplay = $('store-icon-display');
    if (iconDisplay) {
        iconDisplay.innerHTML = info.icon
            ? `<img src="${getFullUrl(info.icon)}" alt="${info.name}" class="w-14 h-14 object-contain bg-white rounded-full border border-pink-100 p-1 shadow-sm">`
            : `<div class="w-14 h-14 bg-gray-100 rounded-full flex items-center justify-center"><i class="fa-solid fa-store text-pink-400 text-xl"></i></div>`;
    }

    if($('store-name-display')) $('store-name-display').textContent = info.name;
    if($('store-desc-display')) $('store-desc-display').textContent = info.desc;
    if($('store-stats-display')) {
        $('store-stats-display').innerHTML = `
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-star text-yellow-500 mr-1"></i>${info.rating}</span>
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-box mr-1"></i>Đã bán ${info.sold}</span>
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-comment mr-1"></i>${info.reviews} đánh giá</span>
        `;
    }
    if($('feedback-title')) $('feedback-title').textContent = `ĐÁNH GIÁ TỪ KHÁCH HÀNG - ${info.name.toUpperCase()}`;

    renderProducts();
    renderFeedback();
}

export function renderCatalog() {
    const container = $('catalog-filter-container');
    if (!container) return;

    let html = `
        <button onclick="filterByCategory('all')"
            class="px-6 py-2 rounded-full font-semibold text-sm whitespace-nowrap transition-all shadow-sm ${App.currentCategory === 'all' ? 'bg-pink-600 text-white shadow-pink-200' : 'bg-white text-gray-600 border border-gray-200 hover:bg-pink-50 hover:text-pink-600'}">
            Tất cả
        </button>
    `;

    if (App.categories && App.categories.length > 0) {
        html += App.categories.map(c => `
            <button onclick="filterByCategory(${c.id})"
                class="px-6 py-2 rounded-full font-semibold text-sm whitespace-nowrap transition-all shadow-sm ${App.currentCategory === c.id ? 'bg-pink-600 text-white shadow-pink-200' : 'bg-white text-gray-600 border border-gray-200 hover:bg-pink-50 hover:text-pink-600'}">
                ${c.icon ? `<i class="${c.icon} mr-2"></i>` : ''}${c.name}
            </button>
        `).join('');
    }

    container.innerHTML = html;
}

export function filterByCategory(categoryId) {
    App.currentCategory = categoryId;
    App.currentVisibleProducts = App.productsPerPage;
    App.searchQuery = '';
    const searchInput = document.getElementById('search-input');
    if (searchInput) searchInput.value = '';
    renderCatalog();
    renderProducts();
}

export function searchProducts(query) {
    App.searchQuery = query.trim();
    App.currentVisibleProducts = App.productsPerPage;
    renderProducts();
}

export function clearSearch() {
    App.searchQuery = '';
    const searchInput = document.getElementById('search-input');
    if (searchInput) searchInput.value = '';
    renderProducts();
}

export function renderProducts() {
    const isSearchMode = App.searchQuery && App.searchQuery.length > 0;
    let allProducts;

    if (isSearchMode) {
        const query = App.searchQuery.toLowerCase();
        allProducts = Object.values(App.storeProducts)
            .flat()
            .filter(p => p.name.toLowerCase().includes(query) || p.category.toLowerCase().includes(query));
    } else {
        allProducts = App.storeProducts[App.currentStore] || [];
        if (App.currentCategory !== 'all') {
            allProducts = allProducts.filter(p => p.category_id === App.currentCategory);
        }
    }

    const container = $('product-list');
    const loadMoreContainer = $('load-more-container');
    const searchHeader = $('search-results-header');

    if (searchHeader) {
        if (isSearchMode) {
            searchHeader.innerHTML = `
                <div class="flex items-center gap-3 mb-2 p-4 bg-pink-50 rounded-2xl border border-pink-100">
                    <i class="fa-solid fa-magnifying-glass text-pink-500 text-lg"></i>
                    <span class="font-semibold text-gray-700">Kết quả cho <span class="text-pink-600">"${App.searchQuery}"</span>: <b>${allProducts.length}</b> sản phẩm</span>
                    <button onclick="clearSearch()" class="ml-auto text-sm text-gray-500 hover:text-red-500 flex items-center gap-1 transition font-semibold">
                        <i class="fa-solid fa-xmark"></i> Xóa
                    </button>
                </div>`;
            searchHeader.classList.remove('hidden');
        } else {
            searchHeader.innerHTML = '';
            searchHeader.classList.add('hidden');
        }
    }

    if (!container) return;

    if (allProducts.length === 0) {
        const emptyMsg = isSearchMode
            ? `<div class="col-span-full py-16 text-center text-gray-400 bg-gray-50/50 rounded-3xl border border-dashed border-gray-200"><i class="fa-solid fa-magnifying-glass text-5xl mb-4 opacity-50"></i><p class="text-lg">Không tìm thấy sản phẩm nào cho "<b>${App.searchQuery}</b>".</p><button onclick="clearSearch()" class="mt-4 px-6 py-2 rounded-full bg-pink-600 text-white text-sm font-semibold hover:bg-pink-700 transition">Xóa tìm kiếm</button></div>`
            : '<div class="col-span-full py-16 text-center text-gray-400 bg-gray-50/50 rounded-3xl border border-dashed border-gray-200"><i class="fa-solid fa-magnifying-glass text-5xl mb-4 opacity-50"></i><p class="text-lg">Không tìm thấy sản phẩm nào trong danh mục này.</p></div>';
        container.innerHTML = emptyMsg;
        if (loadMoreContainer) loadMoreContainer.innerHTML = '';
        return;
    }

    const visibleProducts = allProducts.slice(0, App.currentVisibleProducts);

    container.innerHTML = visibleProducts.map(p => {
        const imageHtml = p.image
            ? `<img loading="lazy" src="${getFullUrl(p.image)}" alt="${p.name}" class="w-full h-full object-cover object-top transition-transform duration-700 group-hover:scale-105">`
            : `<div class="text-gray-200 text-5xl flex items-center justify-center h-full"><i class="fa-solid fa-image"></i></div>`;

        const isWishlisted = App.isLoggedIn && App.wishlist.some(w => w.product_id === p.id);
        const heartClass = isWishlisted ? 'fa-solid text-red-500' : 'fa-regular text-gray-400';
        const storeLabel = isSearchMode ? `<span class="text-[9px] text-gray-400 ml-1 normal-case font-normal">• ${(App.storeInfo[p.store] || {}).name || ''}</span>` : '';

        return `
        <div class="bg-white rounded-2xl p-3 border border-gray-100 shadow-sm hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] hover:-translate-y-1 transition-all duration-300 group flex flex-col h-full relative">
            <div class="h-64 sm:h-72 rounded-xl overflow-hidden mb-4 bg-gray-50 relative">
                ${imageHtml}
                <div class="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                    <button onclick="addToCart(${p.id})" class="bg-white text-pink-600 px-6 py-2.5 rounded-full font-bold shadow-xl transform translate-y-4 group-hover:translate-y-0 transition-all duration-300 hover:bg-pink-600 hover:text-white flex items-center">
                        <i class="fa-solid fa-cart-plus mr-2"></i> Thêm ngay
                    </button>
                </div>
                <button data-wishlist-id="${p.id}" onclick="toggleWishlist(${p.id})" title="Yêu thích" class="absolute top-2 right-2 bg-white/90 backdrop-blur-sm w-8 h-8 rounded-full flex items-center justify-center shadow-sm hover:scale-110 transition z-10">
                    <i class="${heartClass} fa-heart text-sm"></i>
                </button>
            </div>
            <div class="flex flex-col flex-grow px-2 pb-2 text-left">
                <span class="text-[10px] font-bold text-pink-400 mb-1.5 uppercase tracking-wider bg-pink-50 inline-flex items-center w-max px-2 py-0.5 rounded">${p.category}${storeLabel}</span>
                <h3 class="font-semibold text-gray-800 text-base leading-tight mb-3 line-clamp-2" title="${p.name}">${p.name}</h3>

                <div class="mt-auto flex items-end justify-between">
                    <span class="text-xl font-black text-pink-600">${p.price.toLocaleString('en-US')}₫</span>
                    <button onclick="addToCart(${p.id})" class="lg:hidden bg-pink-50 text-pink-600 w-9 h-9 rounded-full flex items-center justify-center hover:bg-pink-600 hover:text-white transition">
                        <i class="fa-solid fa-cart-plus"></i>
                    </button>
                </div>
            </div>
        </div>
        `;
    }).join('');

    if (loadMoreContainer) {
        if (App.currentVisibleProducts < allProducts.length) {
            loadMoreContainer.innerHTML = `
                <button onclick="loadMoreProducts()" class="px-8 py-3 bg-white border border-gray-200 text-gray-700 rounded-full font-semibold hover:bg-gray-50 hover:text-pink-600 transition shadow-sm hover:shadow flex items-center mx-auto">
                    Hiển thị thêm sản phẩm <i class="fa-solid fa-chevron-down ml-2"></i>
                </button>
            `;
        } else {
            loadMoreContainer.innerHTML = '';
        }
    }
}

export function loadMoreProducts() {
    App.currentVisibleProducts += App.productsPerPage;
    renderProducts();
}

export function renderFeedback() {
    const feedbacks = storeFeedback[App.currentStore] || [];
    const container = $('feedback-list');
    if (!container) return;

    if(feedbacks.length === 0) {
         container.innerHTML = '<p class="text-gray-400 italic text-sm">Chưa có đánh giá nào.</p>';
         return;
    }

    container.innerHTML = feedbacks.map(f => `
        <div class="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow transition">
            <div class="flex items-center mb-3">
                <div class="w-10 h-10 bg-gradient-to-br from-pink-400 to-purple-500 rounded-full flex items-center justify-center text-white font-bold mr-3 shadow-sm">${f.avatar}</div>
                <div>
                    <h4 class="font-bold text-gray-800 text-sm">${f.name}</h4>
                    <div class="flex mt-0.5">${Array(5).fill(0).map((_, i) => `<i class="fa-solid fa-star ${i < f.rating ? 'text-yellow-400' : 'text-gray-200'} text-[10px]"></i>`).join('')}</div>
                </div>
            </div>
            <p class="text-gray-600 text-sm leading-relaxed">"${f.comment}"</p>
            <p class="text-[11px] text-gray-400 mt-3 font-medium"><i class="fa-regular fa-clock mr-1"></i>${f.date}</p>
        </div>
    `).join('');
}

export function scrollStoreTabs(direction) {
    const container = $('store-tabs-container');
    if (!container) return;
    const scrollAmount = 320;
    container.scrollBy({ left: direction * scrollAmount, behavior: 'smooth' });
}

export function checkScrollButtons() {
    const container = $('store-tabs-container');
    const btnLeft = $('btn-scroll-left');
    const btnRight = $('btn-scroll-right');

    if (!container || !btnLeft || !btnRight) return;

    btnLeft.disabled = container.scrollLeft <= 5;
    btnLeft.style.opacity = btnLeft.disabled ? '0.3' : '1';

    btnRight.disabled = container.scrollLeft >= (container.scrollWidth - container.clientWidth) - 5;
    btnRight.style.opacity = btnRight.disabled ? '0.3' : '1';
}

import { App, storeFeedback, $, API_BASE_URL } from './config.js';

// Tối ưu ghép chuỗi URL tĩnh
const getFullUrl = (path) => {
    if (!path) return '';
    if (path.startsWith('http')) return path;
    const baseUrl = API_BASE_URL.replace(/\/$/, '');
    return `${baseUrl}${path.startsWith('/') ? path : `/${path}`}`;
};

export function renderStoreTabs() {
    const container = $('store-tabs-container');
    if (!container) return;

    // Tối ưu: map mảng sau đó gán 1 lần
    container.innerHTML = Object.keys(App.storeInfo).map((storeId, index) => {
        const info = App.storeInfo[storeId];
        const activeClass = App.currentStore == storeId ? 'active' : '';
        const textColor = index >= 3 ? 'text-white' : 'text-gray-800';

        const iconHtml = info.icon
            ? `<img src="${getFullUrl(info.icon)}" alt="${info.name}" class="w-12 h-12 object-contain bg-white rounded-full mb-2 border-2 border-pink-200 shadow-sm mx-auto p-1 transition-transform group-hover:scale-110">`
            : `<div class="w-12 h-12 bg-gray-200 rounded-full mb-2 mx-auto flex items-center justify-center text-gray-400"><i class="fa-solid fa-store"></i></div>`;

        return `
        <div class="store-card group ${activeClass}" id="store-tab-${storeId}" onclick="selectStore(${storeId})" style="background: ${info.bg_color}">
            ${iconHtml}
            <div class="store-name ${textColor} font-bold">${info.name}</div>
            <div class="store-stats ${textColor} opacity-90 text-xs mt-1"><i class="fa-solid fa-star text-yellow-300 mr-1"></i>${info.rating} • Đã bán ${info.sold}</div>
        </div>
        `;
    }).join('');
}

export function renderHotDeals() {
    const container = $('hot-deals-container');
    if (!container) return;

    if (!App.hotDeals || App.hotDeals.length === 0) {
        container.innerHTML = '<div class="col-span-full py-10 text-center text-gray-400 bg-gray-50 rounded-2xl"><i class="fa-solid fa-box-open text-4xl mb-3"></i><p>Hiện tại chưa có Deal Hot nào.</p></div>';
        return;
    }

    container.innerHTML = App.hotDeals.map(p => {
        let badgeHtml = '';
        let priceHtml = `<span class="text-xl font-black text-red-600">${p.price.toLocaleString('en-US')}₫</span>`;

        if (p.old_price && p.old_price > p.price) {
            const percent = Math.round((1 - p.price / p.old_price) * 100);
            badgeHtml = `<span class="absolute top-3 left-3 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded shadow-sm z-10">-${percent}%</span>`;
            priceHtml = `
                <span class="text-xl font-black text-red-600">${p.price.toLocaleString('en-US')}₫</span>
                <span class="text-xs text-gray-400 line-through block ml-1">${p.old_price.toLocaleString('en-US')}₫</span>
            `;
        }

        const imageHtml = p.image
            ? `<img loading="lazy" src="${getFullUrl(p.image)}" alt="${p.name}" class="w-full h-full object-cover transition-transform duration-500 hover:scale-110">`
            : `<div class="text-gray-300 text-4xl"><i class="fa-solid fa-image"></i></div>`;

        const isWishlisted = App.isLoggedIn && App.wishlist.some(w => w.product_id === p.id);
        const heartClass = isWishlisted ? 'fa-solid text-red-500' : 'fa-regular text-gray-400';

        return `
        <div class="bg-white p-3 rounded-2xl relative border border-red-100 hover:border-red-400 shadow-sm hover:shadow-lg transition-all cursor-pointer group flex flex-col h-full">
            ${badgeHtml}
            <div class="h-40 sm:h-48 rounded-xl overflow-hidden mb-3 bg-gray-50 flex items-center justify-center relative">
                ${imageHtml}
                <button data-wishlist-id="${p.id}" onclick="toggleWishlist(${p.id})" title="Yêu thích" class="absolute top-2 right-2 bg-white/90 backdrop-blur-sm w-7 h-7 rounded-full flex items-center justify-center shadow-sm hover:scale-110 transition z-10">
                    <i class="${heartClass} fa-heart text-xs"></i>
                </button>
            </div>
            <h3 class="font-bold text-gray-800 text-sm mb-2 line-clamp-2" title="${p.name}">${p.name}</h3>
            <div class="mt-auto flex items-end justify-between">
                <div>${priceHtml}</div>
                <button onclick="addToCart(${p.id})" class="bg-red-50 text-red-500 w-10 h-10 rounded-full flex items-center justify-center hover:bg-red-500 hover:text-white transition shadow-sm z-20 relative">
                    <i class="fa-solid fa-cart-plus"></i>
                </button>
            </div>
        </div>
        `;
    }).join('');
}

export function selectStore(storeId) {
    document.querySelectorAll('.store-card').forEach(card => card.classList.remove('active'));
    const activeTab = $(`store-tab-${storeId}`);
    if (activeTab) activeTab.classList.add('active');

    App.currentStore = storeId;
    App.currentVisibleProducts = App.productsPerPage;

    const info = App.storeInfo[storeId];
    if (!info) return;

    const iconDisplay = $('store-icon-display');
    if (iconDisplay) {
        iconDisplay.innerHTML = info.icon
            ? `<img src="${getFullUrl(info.icon)}" alt="${info.name}" class="w-14 h-14 object-contain bg-white rounded-full border border-pink-100 p-1 shadow-sm">`
            : `<div class="w-14 h-14 bg-gray-100 rounded-full flex items-center justify-center"><i class="fa-solid fa-store text-pink-400 text-xl"></i></div>`;
    }

    if($('store-name-display')) $('store-name-display').textContent = info.name;
    if($('store-desc-display')) $('store-desc-display').textContent = info.desc;
    if($('store-stats-display')) {
        $('store-stats-display').innerHTML = `
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-star text-yellow-500 mr-1"></i>${info.rating}</span>
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-box mr-1"></i>Đã bán ${info.sold}</span>
            <span class="bg-pink-50 text-pink-700 px-3 py-1 rounded-full text-xs font-semibold border border-pink-100"><i class="fa-solid fa-comment mr-1"></i>${info.reviews} đánh giá</span>
        `;
    }
    if($('feedback-title')) $('feedback-title').textContent = `ĐÁNH GIÁ TỪ KHÁCH HÀNG - ${info.name.toUpperCase()}`;

    renderProducts();
    renderFeedback();
}

export function renderCatalog() {
    const container = $('catalog-filter-container');
    if (!container) return;

    let html = `
        <button onclick="filterByCategory('all')"
            class="px-6 py-2 rounded-full font-semibold text-sm whitespace-nowrap transition-all shadow-sm ${App.currentCategory === 'all' ? 'bg-pink-600 text-white shadow-pink-200' : 'bg-white text-gray-600 border border-gray-200 hover:bg-pink-50 hover:text-pink-600'}">
            Tất cả
        </button>
    `;

    if (App.categories && App.categories.length > 0) {
        html += App.categories.map(c => `
            <button onclick="filterByCategory(${c.id})"
                class="px-6 py-2 rounded-full font-semibold text-sm whitespace-nowrap transition-all shadow-sm ${App.currentCategory === c.id ? 'bg-pink-600 text-white shadow-pink-200' : 'bg-white text-gray-600 border border-gray-200 hover:bg-pink-50 hover:text-pink-600'}">
                ${c.icon ? `<i class="${c.icon} mr-2"></i>` : ''}${c.name}
            </button>
        `).join('');
    }

    container.innerHTML = html;
}

export function filterByCategory(categoryId) {
    App.currentCategory = categoryId;
    App.currentVisibleProducts = App.productsPerPage;
    App.searchQuery = '';
    const searchInput = document.getElementById('search-input');
    if (searchInput) searchInput.value = '';
    renderCatalog();
    renderProducts();
}

export function searchProducts(query) {
    App.searchQuery = query.trim();
    App.currentVisibleProducts = App.productsPerPage;
    renderProducts();
}

export function clearSearch() {
    App.searchQuery = '';
    const searchInput = document.getElementById('search-input');
    if (searchInput) searchInput.value = '';
    renderProducts();
}

export function renderProducts() {
    const isSearchMode = App.searchQuery && App.searchQuery.length > 0;
    let allProducts;

    if (isSearchMode) {
        const query = App.searchQuery.toLowerCase();
        allProducts = Object.values(App.storeProducts)
            .flat()
            .filter(p => p.name.toLowerCase().includes(query) || p.category.toLowerCase().includes(query));
    } else {
        allProducts = App.storeProducts[App.currentStore] || [];
        if (App.currentCategory !== 'all') {
            allProducts = allProducts.filter(p => p.category_id === App.currentCategory);
        }
    }

    const container = $('product-list');
    const loadMoreContainer = $('load-more-container');
    const searchHeader = $('search-results-header');

    if (searchHeader) {
        if (isSearchMode) {
            searchHeader.innerHTML = `
                <div class="flex items-center gap-3 mb-2 p-4 bg-pink-50 rounded-2xl border border-pink-100">
                    <i class="fa-solid fa-magnifying-glass text-pink-500 text-lg"></i>
                    <span class="font-semibold text-gray-700">Kết quả cho <span class="text-pink-600">"${App.searchQuery}"</span>: <b>${allProducts.length}</b> sản phẩm</span>
                    <button onclick="clearSearch()" class="ml-auto text-sm text-gray-500 hover:text-red-500 flex items-center gap-1 transition font-semibold">
                        <i class="fa-solid fa-xmark"></i> Xóa
                    </button>
                </div>`;
            searchHeader.classList.remove('hidden');
        } else {
            searchHeader.innerHTML = '';
            searchHeader.classList.add('hidden');
        }
    }

    if (!container) return;

    if (allProducts.length === 0) {
        const emptyMsg = isSearchMode
            ? `<div class="col-span-full py-16 text-center text-gray-400 bg-gray-50/50 rounded-3xl border border-dashed border-gray-200"><i class="fa-solid fa-magnifying-glass text-5xl mb-4 opacity-50"></i><p class="text-lg">Không tìm thấy sản phẩm nào cho "<b>${App.searchQuery}</b>".</p><button onclick="clearSearch()" class="mt-4 px-6 py-2 rounded-full bg-pink-600 text-white text-sm font-semibold hover:bg-pink-700 transition">Xóa tìm kiếm</button></div>`
            : '<div class="col-span-full py-16 text-center text-gray-400 bg-gray-50/50 rounded-3xl border border-dashed border-gray-200"><i class="fa-solid fa-magnifying-glass text-5xl mb-4 opacity-50"></i><p class="text-lg">Không tìm thấy sản phẩm nào trong danh mục này.</p></div>';
        container.innerHTML = emptyMsg;
        if (loadMoreContainer) loadMoreContainer.innerHTML = '';
        return;
    }

    const visibleProducts = allProducts.slice(0, App.currentVisibleProducts);

    container.innerHTML = visibleProducts.map(p => {
        const imageHtml = p.image
            ? `<img loading="lazy" src="${getFullUrl(p.image)}" alt="${p.name}" class="w-full h-full object-cover object-top transition-transform duration-700 group-hover:scale-105">`
            : `<div class="text-gray-200 text-5xl flex items-center justify-center h-full"><i class="fa-solid fa-image"></i></div>`;

        const isWishlisted = App.isLoggedIn && App.wishlist.some(w => w.product_id === p.id);
        const heartClass = isWishlisted ? 'fa-solid text-red-500' : 'fa-regular text-gray-400';
        const storeLabel = isSearchMode ? `<span class="text-[9px] text-gray-400 ml-1 normal-case font-normal">• ${(App.storeInfo[p.store] || {}).name || ''}</span>` : '';

        return `
        <div class="bg-white rounded-2xl p-3 border border-gray-100 shadow-sm hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] hover:-translate-y-1 transition-all duration-300 group flex flex-col h-full relative">
            <div class="h-64 sm:h-72 rounded-xl overflow-hidden mb-4 bg-gray-50 relative">
                ${imageHtml}
                <div class="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                    <button onclick="addToCart(${p.id})" class="bg-white text-pink-600 px-6 py-2.5 rounded-full font-bold shadow-xl transform translate-y-4 group-hover:translate-y-0 transition-all duration-300 hover:bg-pink-600 hover:text-white flex items-center">
                        <i class="fa-solid fa-cart-plus mr-2"></i> Thêm ngay
                    </button>
                </div>
                <button data-wishlist-id="${p.id}" onclick="toggleWishlist(${p.id})" title="Yêu thích" class="absolute top-2 right-2 bg-white/90 backdrop-blur-sm w-8 h-8 rounded-full flex items-center justify-center shadow-sm hover:scale-110 transition z-10">
                    <i class="${heartClass} fa-heart text-sm"></i>
                </button>
            </div>
            <div class="flex flex-col flex-grow px-2 pb-2 text-left">
                <span class="text-[10px] font-bold text-pink-400 mb-1.5 uppercase tracking-wider bg-pink-50 inline-flex items-center w-max px-2 py-0.5 rounded">${p.category}${storeLabel}</span>
                <h3 class="font-semibold text-gray-800 text-base leading-tight mb-3 line-clamp-2" title="${p.name}">${p.name}</h3>

                <div class="mt-auto flex items-end justify-between">
                    <span class="text-xl font-black text-pink-600">${p.price.toLocaleString('en-US')}₫</span>
                    <button onclick="addToCart(${p.id})" class="lg:hidden bg-pink-50 text-pink-600 w-9 h-9 rounded-full flex items-center justify-center hover:bg-pink-600 hover:text-white transition">
                        <i class="fa-solid fa-cart-plus"></i>
                    </button>
                </div>
            </div>
        </div>
        `;
    }).join('');

    if (loadMoreContainer) {
        if (App.currentVisibleProducts < allProducts.length) {
            loadMoreContainer.innerHTML = `
                <button onclick="loadMoreProducts()" class="px-8 py-3 bg-white border border-gray-200 text-gray-700 rounded-full font-semibold hover:bg-gray-50 hover:text-pink-600 transition shadow-sm hover:shadow flex items-center mx-auto">
                    Hiển thị thêm sản phẩm <i class="fa-solid fa-chevron-down ml-2"></i>
                </button>
            `;
        } else {
            loadMoreContainer.innerHTML = '';
        }
    }
}

export function loadMoreProducts() {
    App.currentVisibleProducts += App.productsPerPage;
    renderProducts();
}

export function renderFeedback() {
    const feedbacks = storeFeedback[App.currentStore] || [];
    const container = $('feedback-list');
    if (!container) return;

    if(feedbacks.length === 0) {
         container.innerHTML = '<p class="text-gray-400 italic text-sm">Chưa có đánh giá nào.</p>';
         return;
    }

    container.innerHTML = feedbacks.map(f => `
        <div class="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow transition">
            <div class="flex items-center mb-3">
                <div class="w-10 h-10 bg-gradient-to-br from-pink-400 to-purple-500 rounded-full flex items-center justify-center text-white font-bold mr-3 shadow-sm">${f.avatar}</div>
                <div>
                    <h4 class="font-bold text-gray-800 text-sm">${f.name}</h4>
                    <div class="flex mt-0.5">${Array(5).fill(0).map((_, i) => `<i class="fa-solid fa-star ${i < f.rating ? 'text-yellow-400' : 'text-gray-200'} text-[10px]"></i>`).join('')}</div>
                </div>
            </div>
            <p class="text-gray-600 text-sm leading-relaxed">"${f.comment}"</p>
            <p class="text-[11px] text-gray-400 mt-3 font-medium"><i class="fa-regular fa-clock mr-1"></i>${f.date}</p>
        </div>
    `).join('');
}

export function scrollStoreTabs(direction) {
    const container = $('store-tabs-container');
    if (!container) return;
    const scrollAmount = 320;
    container.scrollBy({ left: direction * scrollAmount, behavior: 'smooth' });
}

export function checkScrollButtons() {
    const container = $('store-tabs-container');
    const btnLeft = $('btn-scroll-left');
    const btnRight = $('btn-scroll-right');

    if (!container || !btnLeft || !btnRight) return;

    btnLeft.disabled = container.scrollLeft <= 5;
    btnLeft.style.opacity = btnLeft.disabled ? '0.3' : '1';

    btnRight.disabled = container.scrollLeft >= (container.scrollWidth - container.clientWidth) - 5;
    btnRight.style.opacity = btnRight.disabled ? '0.3' : '1';
}

import { App, $ } from './config.js';

// Quản lý thông báo (Notification) không bị tràn màn hình nếu bấm liên tục
export function showNotification(message, type = 'success') {
    const notification = document.createElement('div');
    const bgClass = type === 'success' ? 'bg-white' : 'bg-red-50';
    const icon = type === 'success' ? 'fa-circle-check text-green-600' : 'fa-circle-exclamation text-orange-500';

    notification.className = `fixed top-20 right-4 ${bgClass} p-4 rounded-xl shadow-[0_10px_40px_rgba(0,0,0,0.1)] z-[9999] animate-bounce flex items-center border ${type === 'success' ? 'border-green-100' : 'border-red-200'}`;
    notification.innerHTML = `<i class="fa-regular ${icon} text-xl mr-3"></i><span class="font-semibold text-gray-800">${message}</span>`;

    document.body.appendChild(notification);

    // Tự động xóa mượt mà
    setTimeout(() => {
        notification.classList.add('opacity-0', 'transition-opacity', 'duration-500');
        setTimeout(() => notification.remove(), 500);
    }, 2500);
}

// Tối ưu hàm ẩn tất cả các view chỉ với 1 vòng lặp an toàn
export const hideAllViews = () => {
    const views = [
        'view-home',
        'view-cart',
        'view-checkout',
        'view-success',
        'view-login',
        'view-register',
        'view-account',
        'view-orders',
        'view-vendor-apply',
        'view-shipper-apply'
    ];
    views.forEach(id => {
        const el = $(id);
        if (el) el.classList.add('hide');
    });
};

// Cập nhật giao diện xác thực an toàn
export function updateAuthUI() {
    const authBtns = $('auth-buttons-container');
    const userProf = $('user-profile-container');

    if (App.isLoggedIn) {
        if (authBtns) authBtns.classList.add('hidden');
        if (userProf) userProf.classList.remove('hidden');
        if ($('acc-name')) $('acc-name').value = App.currentUser?.name || '';
        if ($('acc-email')) $('acc-email').value = App.currentUser?.email || '';
        const roleBadge = $('user-role-badge');
        if (roleBadge) {
            const roleText = App.currentUser?.role || 'CUSTOMER';
            roleBadge.textContent = roleText;
        }
    } else {
        if (authBtns) authBtns.classList.remove('hidden');
        if (userProf) userProf.classList.add('hidden');
    }
}

// Hàm tiện ích chuyển trang (Tái sử dụng logic chung)
const switchView = (viewId) => {
    hideAllViews();
    const view = $(viewId);
    if(view) view.classList.remove('hide');
    window.scrollTo({ top: 0, behavior: 'smooth' });
};

export const showHome = () => switchView('view-home');
export const showLogin = () => switchView('view-login');
export const showRegister = () => switchView('view-register');
export const showAccount = () => {
    switchView('view-account');
    if (typeof window.loadAccountWorkspace === 'function') {
        window.loadAccountWorkspace();
    }
};
export const showVendorApply = () => {
    if (!App.isLoggedIn) {
        showNotification('Vui lòng đăng nhập trước khi nộp đơn Người bán.', 'error');
        showLogin();
        return;
    }
    switchView('view-vendor-apply');
};
export const showShipperApply = () => {
    if (!App.isLoggedIn) {
        showNotification('Vui lòng đăng nhập trước khi nộp đơn vận chuyển.', 'error');
        showLogin();
        return;
    }
    switchView('view-shipper-apply');
};

